package io.github.njw3995.fabricmmo.core.administration;

import io.github.njw3995.fabricmmo.api.NamespacedId;import io.github.njw3995.fabricmmo.core.persistence.PlayerProgressionData;import io.github.njw3995.fabricmmo.core.persistence.ProgressionStore;import io.github.njw3995.fabricmmo.core.persistence.StoredSkillProgress;import java.io.BufferedReader;import java.io.IOException;import java.nio.charset.StandardCharsets;import java.nio.file.Files;import java.nio.file.Path;import java.util.LinkedHashMap;import java.util.Map;import java.util.UUID;
/** Controlled import helper for legacy rows. Exact upstream mcmmo.users column mapping is still UNVERIFIED. */
public final class LegacyFlatFileImporter { private final ProgressionStore store;public LegacyFlatFileImporter(ProgressionStore store){this.store=store;}public int importSimple(Path file,Map<Integer,NamespacedId> levelColumns,Map<Integer,NamespacedId> xpColumns)throws IOException{int count=0;try(BufferedReader reader=Files.newBufferedReader(file,StandardCharsets.UTF_8)){String line;while((line=reader.readLine())!=null){if(line.isBlank()||line.startsWith("#"))continue;String[] c=line.split(":",-1);UUID id;try{id=UUID.fromString(c[0]);}catch(IllegalArgumentException e){continue;}Map<NamespacedId,StoredSkillProgress> skills=new LinkedHashMap<>();for(var entry:levelColumns.entrySet()){if(entry.getKey()>=c.length)continue;int level=Integer.parseInt(c[entry.getKey()]);int xpIndex=xpColumns.entrySet().stream().filter(x->x.getValue().equals(entry.getValue())).map(Map.Entry::getKey).findFirst().orElse(-1);double xp=xpIndex>=0&&xpIndex<c.length?Double.parseDouble(c[xpIndex]):0;skills.put(entry.getValue(),new StoredSkillProgress(level,xp));}store.save(new PlayerProgressionData(id,1,skills));count++;}}return count;} }
